import{_ as e,o as r,c as i,a2 as t}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"美股定投","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-hours-and-rules/us-regular-investment.md","filePath":"zh-CN/stock-trading/trading-hours-and-rules/us-regular-investment.md"}'),l={name:"stock-trading/trading-hours-and-rules/us-regular-investment.md"};function o(n,a,h,s,d,u){return r(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="美股定投" tabindex="-1">美股定投 <a class="header-anchor" href="#美股定投" aria-label="Permalink to &quot;美股定投&quot;">​</a></h1><p>股票定投是一种投资策略，指投资者在固定时间以固定金额投资于特定股票。适合无需深入研究个股、希望长期参与股市的投资者。</p><p>当前仅美股市场支持定投，大部分支持美股碎股交易的股票都支持定投。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><ul><li>方式一：长桥 App - 个股详情 - 更多 - 定投，创建该股票的定投计划</li><li>方式二：长桥 App - 资产 - 全部功能 - 股票定投，进入定投界面</li></ul><h2 id="创建定投计划" tabindex="-1">创建定投计划 <a class="header-anchor" href="#创建定投计划" aria-label="Permalink to &quot;创建定投计划&quot;">​</a></h2><h3 id="定投周期" tabindex="-1">定投周期 <a class="header-anchor" href="#定投周期" aria-label="Permalink to &quot;定投周期&quot;">​</a></h3><p>频率支持每日、每周、每两周、每月。界面展示时区为港股市场 HKT 时间，美股市场美东时间。</p><h3 id="定投金额" tabindex="-1">定投金额 <a class="header-anchor" href="#定投金额" aria-label="Permalink to &quot;定投金额&quot;">​</a></h3><p>只能输入整数，US 市场标的默认 USD，最低金额为 10 美元。定投采用市价单执行，并预留部分资金用于支付交易费用，因此实际投入金额会略低于设定值。</p><h3 id="融资选项" tabindex="-1">融资选项 <a class="header-anchor" href="#融资选项" aria-label="Permalink to &quot;融资选项&quot;">​</a></h3><p>允许融资开关默认关闭，开启需二次确认。若账户余额不足，定投计划将自动启用融资，可能产生利息。</p><p>余额不足（且未开启融资）时，当次定投创建失败，可在定投记录中查看失败原因并收到消息推送。连续失败三次定投计划将自动暂停。</p><h2 id="定投计划维护" tabindex="-1">定投计划维护 <a class="header-anchor" href="#定投计划维护" aria-label="Permalink to &quot;定投计划维护&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 股票定投，可进行以下操作：</p><ul><li>查看累计定投金额</li><li>管理定投状态：修改、暂停、恢复、终止</li><li>查看定投详情：每笔定投的时间、成交价、数量、成交金额（定投失败会记录失败原因）</li></ul><p>累计盈亏基于所有定投股票的买入成本与当前价值计算，不反映手动卖出操作对盈亏的影响。</p><h2 id="查看定投提醒与订单记录" tabindex="-1">查看定投提醒与订单记录 <a class="header-anchor" href="#查看定投提醒与订单记录" aria-label="Permalink to &quot;查看定投提醒与订单记录&quot;">​</a></h2><ul><li>定投通知：长桥 App - 右上角通知 - 股票定投</li><li>订单记录：长桥 App - 资产 - 全部功能 - 订单记录（定投订单会有定投标识）</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading/交易时间与规则/美股交易规则与结算">美股交易规则与结算</a> — 美股交易时段</li><li><a href="/wiki/stock-trading/交易时间与规则/美股卖空">美股卖空</a> — 相关交易规则</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/stock-trading">股票交易</a></li><li><a href="/wiki/stock-trading/trading-hours-and-rules">交易市场与规则</a></li></ul>',23)])])}const k=e(l,[["render",o]]);export{p as __pageData,k as default};
